SELECT count(*) FROM title, kind_type, movie_keyword, keyword, movie_companies, company_type, movie_info, company_name WHERE title.kind_id = kind_type.id AND movie_keyword.movie_id = title.id AND movie_keyword.keyword_id = keyword.id AND movie_companies.movie_id = title.id AND movie_companies.company_type_id = company_type.id AND movie_info.movie_id = title.id AND movie_companies.company_id = company_name.id;